import base64


def _decode(data, w, h):
    """Decode base64 RGBA data into list of rows of (r,g,b) or None."""
    raw = base64.b64decode(data)
    rows = []
    for y in range(h):
        row = []
        for x in range(w):
            off = (y * w + x) * 4
            r, g, b, a = raw[off], raw[off+1], raw[off+2], raw[off+3]
            row.append((r, g, b) if a > 64 else None)
        rows.append(row)
    return rows


def _decode_static(entry):
    """Decode a static sprite entry {w, h, data} -> pixel rows."""
    return _decode(entry["data"], entry["w"], entry["h"])


