def get_cat_sprites(cat_key):
    """Return {anim_name: [list of decoded frames]} for a cat."""
    data = _CAT_DATA.get(cat_key, {})
    result = {}
    for anim, info in data.items():
        result[anim] = [_decode(f, info['w'], info['h']) for f in info['frames']]
    return result


